proof fn phi_4_lemma_view_no_range_guard(cm: &CommitMask, i: int)
    requires
        cm@.contains(i),
    ensures
        ({
            let a = i / usize::BITS as int;
            let b = (i % usize::BITS as int) as usize;
            &&& a * 64 + b == i
            &&& is_bit_set(cm.mask[a], b)
        }),
{
    cm.lemma_view();
}

proof fn phi_5_lemma_change_one_entry_no_new_mask_constraint(cm1: &CommitMask, cm2: &CommitMask)
    requires
        cm1.mask[0] == 0,
        cm2.mask[0] == !0usize,
        forall|j: int| 0 < j < 8 ==> cm2.mask[j] == cm1.mask[j],
    ensures
        cm2@ == cm1@.union(Set::new(|b: usize| b < 64 && is_bit_set(!0usize, b)).map(|b: usize| 64 * 0 + b)),
{
    cm1.lemma_change_one_entry(cm2, 0);
